import{_ as i}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as t,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Tag automatici","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/auto-tagging.md","filePath":"it-IT/Other/auto-tagging.md","lastUpdated":1781962217000}'),l={name:"it-IT/Other/auto-tagging.md"};function r(s,a,c,p,d,g){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="tag-automatici" tabindex="-1">Tag automatici <a class="header-anchor" href="#tag-automatici" aria-label="Permalink to &quot;Tag automatici&quot;">​</a></h1><p>I tag automatici si configurano in:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Generano automaticamente tag immagine, utili per ricerca, filtro della Random Image API, gallery pubblica e controllo accesso basato sul rating.</p><h2 id="cosa-puo-fare" tabindex="-1">Cosa può fare <a class="header-anchor" href="#cosa-puo-fare" aria-label="Permalink to &quot;Cosa può fare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funzione</th><th>Descrizione</th></tr></thead><tbody><tr><td>Tag contenuto</td><td>Aggiunge tag per persone, scene, oggetti, stile artistico e contenuti visivi simili.</td></tr><tr><td>Tag personaggi</td><td>Utile per anime, illustrazioni e immagini con personaggi riconoscibili.</td></tr><tr><td>Tag orientamento</td><td>Aggiunge <code>landscape</code>, <code>portrait</code> o <code>square</code>.</td></tr><tr><td>Rating immagine</td><td>Salva risultati <code>G/S/Q/E</code> per contenuto generale, sensibile, dubbio o esplicito.</td></tr><tr><td>Tag su upload</td><td>Le nuove immagini entrano automaticamente nel flusso di tagging.</td></tr><tr><td>Tag in blocco</td><td>Aggiunge tag alle vecchie immagini in tutte le cartelle o in cartelle selezionate.</td></tr></tbody></table><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><p>Prepara almeno un URL Hugging Face Space accessibile.</p><p>L&#39;approccio consigliato è duplicare lo Space <code>wd-tagger</code> di SmilingWolf nel tuo account Hugging Face:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Puoi usare temporaneamente lo Space pubblico, ma gli Space pubblici sono condivisi da molti utenti e possono avere coda, rallentamenti o indisponibilità. Una copia nel tuo account è più stabile per l&#39;uso continuativo.</p><h2 id="duplicare-lo-space-di-smilingwolf" tabindex="-1">Duplicare lo Space di SmilingWolf <a class="header-anchor" href="#duplicare-lo-space-di-smilingwolf" aria-label="Permalink to &quot;Duplicare lo Space di SmilingWolf&quot;">​</a></h2><ol><li>Accedi a Hugging Face.</li><li>Apri <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+i+`" alt="Space pubblico SmilingWolf" loading="lazy"></p><ol start="3"><li>Clicca sul menu con tre puntini in alto a destra.</li><li>Scegli <code>Duplicate this Space</code>.</li><li>Mantieni il nome predefinito o scegline uno tuo, per esempio <code>wd-tagger</code>.</li><li>Imposta la visibilità su <code>Public</code>. Gli Space pubblici sono più semplici da chiamare per ImgBed.</li><li>All&#39;inizio lascia l&#39;hardware gratuito predefinito. Aggiorna solo se la coda diventa evidente.</li><li>Crea lo Space e attendi la fine della build.</li></ol><p>Quando la build è terminata, apri la pagina del tuo Space. L&#39;URL di solito è:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Copia l&#39;indirizzo del browser e incollalo in <code>Space URLs</code> in ImgBed.</p><h2 id="inserire-piu-space-url" tabindex="-1">Inserire più Space URL <a class="header-anchor" href="#inserire-piu-space-url" aria-label="Permalink to &quot;Inserire più Space URL&quot;">​</a></h2><p>Inserisci un URL per riga.</p><p>Esempi:</p><table tabindex="0"><thead><tr><th>Valore</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Space pubblico SmilingWolf, buono per test temporanei.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL di una pagina Space copiata.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Il tuo Space duplicato.</td></tr></tbody></table><p>Puoi inserire più URL. ImgBed li usa insieme e può migliorare la velocità.</p><p>Se uno Space è temporaneamente non disponibile, gli altri possono continuare a elaborare.</p><h2 id="impostazioni" tabindex="-1">Impostazioni <a class="header-anchor" href="#impostazioni" aria-label="Permalink to &quot;Impostazioni&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Consiglio</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Inserisci gli URL preparati. Almeno uno è necessario.</td></tr><tr><td>Cartella target</td><td>Lascia vuoto per tutte le cartelle. Seleziona una cartella solo per elaborare una directory specifica.</td></tr><tr><td>Modello riconoscimento</td><td>Lascia <code>wd-swinv2-tagger-v3</code> come default.</td></tr><tr><td>Soglia tag generali</td><td>Il valore predefinito va bene per la maggior parte delle immagini. Più basso genera più tag, più alto meno tag.</td></tr><tr><td>Soglia tag personaggi</td><td>Default prudente, riduce tag personaggio errati.</td></tr><tr><td>Soglia automatica <code>MCut</code></td><td>Lascia disattivata all&#39;inizio. Attivala se vuoi che il modello decida automaticamente il numero di tag.</td></tr><tr><td>Tag automatici su upload</td><td>Attiva se vuoi tag sulle nuove immagini appena caricate.</td></tr><tr><td>Avvia tagging</td><td>Esegue manualmente il tagging in blocco delle vecchie immagini.</td></tr></tbody></table><h2 id="valori-iniziali-consigliati" tabindex="-1">Valori iniziali consigliati <a class="header-anchor" href="#valori-iniziali-consigliati" aria-label="Permalink to &quot;Valori iniziali consigliati&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Valore consigliato</th></tr></thead><tbody><tr><td>Modello riconoscimento</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>Soglia tag generali</td><td><code>0.35</code></td></tr><tr><td>Soglia tag personaggi</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Disattivato all&#39;inizio</td></tr><tr><td>Tag su upload</td><td>Attiva se serve</td></tr></tbody></table><p>Se i tag sono troppi, alza leggermente la soglia generale.</p><p>Se sono troppo pochi, abbassala leggermente.</p><h2 id="tagging-in-blocco" tabindex="-1">Tagging in blocco <a class="header-anchor" href="#tagging-in-blocco" aria-label="Permalink to &quot;Tagging in blocco&quot;">​</a></h2><ol><li>Compila <code>Space URLs</code>.</li><li>Seleziona una cartella target.</li><li>Clicca avvia tagging.</li><li>Attendi il completamento.</li></ol><p>Se la cartella target è vuota, ImgBed elabora tutte le cartelle.</p><p>Il tagging in blocco è ideale per immagini già presenti. Per le nuove immagini, abilita tag automatici su upload.</p><h2 id="tag-automatici-su-upload" tabindex="-1">Tag automatici su upload <a class="header-anchor" href="#tag-automatici-su-upload" aria-label="Permalink to &quot;Tag automatici su upload&quot;">​</a></h2><p>Dopo l&#39;abilitazione, le nuove immagini caricate chiamano automaticamente gli <code>Space URLs</code> configurati.</p><p>È adatto all&#39;uso a lungo termine.</p><p>Se lo Space è in coda, l&#39;upload può comunque terminare prima e il tagging proseguire dopo.</p><h2 id="quali-immagini-vengono-elaborate" tabindex="-1">Quali immagini vengono elaborate <a class="header-anchor" href="#quali-immagini-vengono-elaborate" aria-label="Permalink to &quot;Quali immagini vengono elaborate&quot;">​</a></h2><p>Il tagging automatico elabora soprattutto file immagine.</p><p>Le immagini che hanno già tag completi, orientamento, rating, larghezza e altezza vengono saltate per evitare chiamate inutili allo Space.</p><p>Quando possibile, ImgBed riempie solo le informazioni mancanti. Per esempio, se manca solo l&#39;orientamento, prova ad aggiungerlo senza avviare l&#39;intero flusso di tag contenuto.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="perche-duplicare-il-mio-space" tabindex="-1">Perché duplicare il mio Space? <a class="header-anchor" href="#perche-duplicare-il-mio-space" aria-label="Permalink to &quot;Perché duplicare il mio Space?&quot;">​</a></h3><p>Gli Space pubblici sono condivisi da molti utenti. Una copia tua viene usata principalmente dal tuo sito ImgBed, quindi di solito è più veloce e affidabile.</p><h3 id="lo-space-continua-ad-avviarsi" tabindex="-1">Lo Space continua ad avviarsi <a class="header-anchor" href="#lo-space-continua-ad-avviarsi" aria-label="Permalink to &quot;Lo Space continua ad avviarsi&quot;">​</a></h3><p>Dopo la prima creazione o dopo un lungo periodo inattivo, uno Space può richiedere tempo per avviarsi.</p><p>Apri prima la pagina dello Space. Quando riconosce normalmente un&#39;immagine, torna in ImgBed e avvia il tagging.</p><h3 id="come-copio-l-url-dello-space" tabindex="-1">Come copio l&#39;URL dello Space? <a class="header-anchor" href="#come-copio-l-url-dello-space" aria-label="Permalink to &quot;Come copio l&#39;URL dello Space?&quot;">​</a></h3><p>Apri la pagina Hugging Face Space e copia l&#39;indirizzo del browser.</p><p>Esempi:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="posso-aggiungere-piu-space" tabindex="-1">Posso aggiungere più Space? <a class="header-anchor" href="#posso-aggiungere-piu-space" aria-label="Permalink to &quot;Posso aggiungere più Space?&quot;">​</a></h3><p>Sì. Inserisci un URL per riga.</p><p>Più Space elaborano immagini insieme e sono utili quando hai molte immagini.</p><h3 id="perche-i-tag-sono-in-inglese" tabindex="-1">Perché i tag sono in inglese? <a class="header-anchor" href="#perche-i-tag-sono-in-inglese" aria-label="Permalink to &quot;Perché i tag sono in inglese?&quot;">​</a></h3><p>I modelli SmilingWolf restituiscono tag in inglese. È normale.</p><p>I tag servono soprattutto per ricerca, filtri, Random Image API e gallery pubblica.</p><h3 id="a-cosa-servono-i-rating" tabindex="-1">A cosa servono i rating? <a class="header-anchor" href="#a-cosa-servono-i-rating" aria-label="Permalink to &quot;A cosa servono i rating?&quot;">​</a></h3><p>I rating lavorano con la modalità di accesso nelle impostazioni di sicurezza.</p><p>Per esempio, quando l&#39;accesso visitatore è limitato per età, navigazione pubblica e funzioni random filtrano le immagini secondo quelle regole.</p><h2 id="flusso-rapido" tabindex="-1">Flusso rapido <a class="header-anchor" href="#flusso-rapido" aria-label="Permalink to &quot;Flusso rapido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Accedi a Hugging Face</span></span>
<span class="line"><span>-&gt; Apri SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplica lo Space</span></span>
<span class="line"><span>-&gt; Attendi la build</span></span>
<span class="line"><span>-&gt; Copia l&#39;URL del tuo Space</span></span>
<span class="line"><span>-&gt; Inserisci Space URLs in ImgBed</span></span>
<span class="line"><span>-&gt; Scegli modello e soglie</span></span>
<span class="line"><span>-&gt; Avvia tagging o abilita tag automatici su upload</span></span></code></pre></div>`,63)])])}const b=e(l,[["render",r]]);export{h as __pageData,b as default};
